const patrimonioNorm = String(
  row.patrimonio_normalizado ?? row.patrimonio ?? ''
)
  .normalize('NFKC')
  .trim()
  .toUpperCase()
  .replace(/\s+/g, ' ');

const agoraWorkflow = new Date();
const dataInicio = new Date(agoraWorkflow.getTime() - 7 * 24 * 60 * 60 * 1000);
const dataEvento = row.data_evento ? new Date(row.data_evento) : null;

// Função para retornar somente YYYY-MM-DD
const toDateOnly = (date) => {
  return date.toISOString().slice(0, 10);
};

return [
  {
    json: {
      patrimonio_norm: patrimonioNorm,
      data_inicio_hist: dataInicio.toISOString(),
      data_fim_hist: agoraWorkflow.toISOString(),
      data_inicio_hist_date: toDateOnly(dataInicio),
      data_fim_hist_date: toDateOnly(agoraWorkflow),
      agora_workflow: agoraWorkflow.toISOString(),
      data_evento_referencia: dataEvento ? dataEvento.toISOString() : null,
      id_disparo_atual: row.id_disparo ?? null,
      id_cliente_atual: row.id_cliente ?? null
    }
  }
];

const historico = $input.all();
const atual = $('Get Row Supabase').first().json;

const eventoAtual = String(atual.evento_codigo ?? '').trim();
const zonaAtual = String(atual.zona ?? '').trim();
const agrupamentoAtual = String(atual.agrupamento ?? '').trim();

const totalEventos = historico.length;

const mesmoCodigo = historico.filter(item =>
  String(item.json.evento_codigo ?? '').trim() === eventoAtual
).length;

const mesmaZona = historico.filter(item =>
  String(item.json.zona ?? '').trim() === zonaAtual
).length;

const mesmoAgrupamento = historico.filter(item =>
  String(item.json.agrupamento ?? '').trim() === agrupamentoAtual
).length;

// Monta contagem por horário HH:MM
const contagemHorarios = {};

for (const item of historico) {
  const hora = String(item.json.hora_evento ?? '').trim();
  const hhmm = hora ? hora.slice(0, 5) : 'SEM_HORA';
  contagemHorarios[hhmm] = (contagemHorarios[hhmm] || 0) + 1;
}

const horariosRecorrentes = Object.entries(contagemHorarios)
  .filter(([hora, qtd]) => hora !== 'SEM_HORA' && qtd >= 2)
  .map(([hora, qtd]) => ({ hora, quantidade: qtd }))
  .sort((a, b) => b.quantidade - a.quantidade);

// Eventos relevantes resumidos
const eventosRelevantes = historico.slice(0, 20).map(item => ({
  id_disparo: item.json.id_disparo ?? null,
  data_evento: item.json.data_evento ?? null,
  hora_evento: item.json.hora_evento ?? null,
  evento_codigo: item.json.evento_codigo ?? null,
  agrupamento: item.json.agrupamento ?? null,
  zona: item.json.zona ?? null,
  desc_evento: item.json.desc_evento ?? null
}));

// ═══════════════════════════════════════════════════════════
// LÓGICA E130/9013 — Descarte de E130 com 9013 em ≤ 5 min
// ═══════════════════════════════════════════════════════════

// Filtrar apenas E130 na mesma zona
const e130MesmaZona = historico.filter(item => {
  const cod = String(item.json.evento_codigo ?? '').trim().toUpperCase();
  const z = String(item.json.zona ?? '').trim();
  return cod === 'E130' && z === zonaAtual;
});

const e130Total7d = e130MesmaZona.length;

// Identificar pares E130→9013 (restauração em ≤ 5 min = abertura+fechamento normal)
const todos9013 = historico.filter(item => {
  const cod = String(item.json.evento_codigo ?? '').trim();
  return cod === '9013';
});

let e130Descartados = 0;

for (const e130 of e130MesmaZona) {
  const tsE130 = new Date(e130.json.data_evento + 'T' + (e130.json.hora_evento || '00:00:00'));
  if (isNaN(tsE130.getTime())) continue;

  const zonaE130 = String(e130.json.zona ?? '').trim();

  // Procurar um 9013 na mesma zona em até 5 min após o E130
  const temPar9013 = todos9013.some(r => {
    const zonaR = String(r.json.zona ?? '').trim();
    if (zonaR !== zonaE130) return false;

    const tsR = new Date(r.json.data_evento + 'T' + (r.json.hora_evento || '00:00:00'));
    if (isNaN(tsR.getTime())) return false;

    const diffMs = tsR.getTime() - tsE130.getTime();
    return diffMs >= 0 && diffMs <= 5 * 60 * 1000; // 0 a 5 min
  });

  if (temPar9013) e130Descartados++;
}

const e130Validos7d = e130Total7d - e130Descartados;

// Dias distintos com E130 válido (sem par 9013)
const diasComE130Valido = new Set();
for (const e130 of e130MesmaZona) {
  const tsE130 = new Date(e130.json.data_evento + 'T' + (e130.json.hora_evento || '00:00:00'));
  if (isNaN(tsE130.getTime())) continue;

  const zonaE130 = String(e130.json.zona ?? '').trim();
  const temPar = todos9013.some(r => {
    const zonaR = String(r.json.zona ?? '').trim();
    if (zonaR !== zonaE130) return false;
    const tsR = new Date(r.json.data_evento + 'T' + (r.json.hora_evento || '00:00:00'));
    if (isNaN(tsR.getTime())) return false;
    const diffMs = tsR.getTime() - tsE130.getTime();
    return diffMs >= 0 && diffMs <= 5 * 60 * 1000;
  });

  if (!temPar) {
    const dia = String(e130.json.data_evento ?? '').slice(0, 10);
    if (dia) diasComE130Valido.add(dia);
  }
}

const diasDistintosE130Validos7d = diasComE130Valido.size;

// ═══════════════════════════════════════════════════════════

const primeiraOcorrencia = totalEventos === 0;
const recorrenciaElevadaMesmaZona = mesmaZona >= 3;
const recorrenciaElevadaMesmoCodigo = mesmoCodigo >= 3;

let resumoTexto = '';

if (totalEventos === 0) {
  resumoTexto = 'Não foram encontrados eventos anteriores para este patrimônio nos últimos 7 dias.';
} else {
  resumoTexto =
    `Foram encontrados ${totalEventos} eventos para este patrimônio nos últimos 7 dias. ` +
    `${mesmoCodigo} possuem o mesmo código do evento atual (${eventoAtual || 'N/D'}). ` +
    `${mesmaZona} ocorreram na mesma zona (${zonaAtual || 'N/D'}). ` +
    `${mesmoAgrupamento} pertencem ao mesmo agrupamento (${agrupamentoAtual || 'N/D'}).`;

  if (horariosRecorrentes.length > 0) {
    const topHorarios = horariosRecorrentes
      .slice(0, 3)
      .map(h => `${h.hora} (${h.quantidade}x)`)
      .join(', ');
    resumoTexto += ` Há recorrência de horário em: ${topHorarios}.`;
  }

  if (recorrenciaElevadaMesmaZona) resumoTexto += ' Há recorrência elevada na mesma zona.';
  if (recorrenciaElevadaMesmoCodigo) resumoTexto += ' Há recorrência elevada do mesmo código de evento.';

  if (e130Validos7d > 0) {
    resumoTexto += ` E130 na mesma zona: ${e130Total7d} total, ${e130Descartados} descartados (9013 em ≤5min), ${e130Validos7d} válidos em ${diasDistintosE130Validos7d} dia(s) distinto(s).`;
  }
}

return [
  {
    json: {
      historico_resumo: {
        janela_dias: 7,
        total_eventos_periodo: totalEventos,
        mesmo_codigo_evento: mesmoCodigo,
        mesma_zona: mesmaZona,
        mesmo_agrupamento: mesmoAgrupamento,
        primeira_ocorrencia: primeiraOcorrencia,
        recorrencia_elevada_mesma_zona: recorrenciaElevadaMesmaZona,
        recorrencia_elevada_mesmo_codigo: recorrenciaElevadaMesmoCodigo,
        horarios_recorrentes: horariosRecorrentes,
        eventos_relevantes: eventosRelevantes,
        resumo_historico_texto: resumoTexto,
        // Campos E130
        e130_total_7d: e130Total7d,
        e130_descartados_9013_5m_7d: e130Descartados,
        e130_validos_sensor_7d: e130Validos7d,
        dias_distintos_e130_validos_7d: diasDistintosE130Validos7d
      }
    }
  }
];

const j = $input.item.json;

const score = Number(j.score || 0);
const historico = j.historico_resumo || {};
const globalAnalysis = j.global_analysis || {};
const recorrencia = globalAnalysis.analise_recorrencia || {};
const evento = j.evento_enriquecido || {};
const pendencia = j.pendencia || {};

const codigoEvento =
  j.codigo_evento ||
  pendencia.evento_codigo ||
  evento.codigo ||
  null;

const setor =
  j.setor ||
  pendencia.setor ||
  (pendencia.raw ? JSON.parse(pendencia.raw).setor : null) ||
  null;

const zona =
  j.zona ||
  pendencia.zona ||
  (pendencia.raw ? JSON.parse(pendencia.raw).zona : null) ||
  null;

const patrimonio =
  j.patrimonio_norm ||
  j.patrimonio ||
  pendencia.patrimonio_normalizado ||
  pendencia.patrimonio ||
  (pendencia.raw ? JSON.parse(pendencia.raw).patrimonio : null) ||
  null;

const endereco =
  j.endereco ||
  pendencia.endereco ||
  (pendencia.raw ? JSON.parse(pendencia.raw).endereco : null) ||
  null;

const descricaoEvento =
  j.descricao_evento ||
  pendencia.desc_evento ||
  evento.descricao_iris ||
  (pendencia.raw ? JSON.parse(pendencia.raw).descEvento : null) ||
  null;

const mesmoCodigo7d = Number(historico.mesmo_codigo_evento || recorrencia.qtd_mesmo_evento_7d || 0);
const mesmoSetor7d = Number(historico.mesmo_setor || 0);
const mesmaZona7d = Number(historico.mesma_zona || recorrencia.qtd_mesma_zona_7d || 0);

// Novos campos E130 do Resumo Histórico IA
const e130Validos7d = Number(historico.e130_validos_sensor_7d || 0);
const diasDistintosE130Validos7d = Number(historico.dias_distintos_e130_validos_7d || 0);
const e130Total7d = Number(historico.e130_total_7d || 0);
const e130Descartados7d = Number(historico.e130_descartados_9013_5m_7d || 0);

const recorrenciaElevadaMesmoSetor = Boolean(historico.recorrencia_elevada_mesmo_setor === true);
const recorrenciaElevadaMesmoCodigo = Boolean(historico.recorrencia_elevada_mesmo_codigo === true);
const recorrenciaElevadaMesmaZona = Boolean(historico.recorrencia_elevada_mesma_zona === true);
const primeiraOcorrencia = Boolean(historico.primeira_ocorrencia === true);

const hipotese = (j.hipotese || "").toLowerCase();
const observacaoRecorrencia = (recorrencia.observacao || "").toLowerCase();
const pontosAtencao = Array.isArray(globalAnalysis.pontos_de_atencao)
  ? globalAnalysis.pontos_de_atencao.join(" | ").toLowerCase()
  : "";

let abrir_os = false;
let tipo_os = null;
let motivo_os = null;
let prioridade_os = "Baixa";
let categoria_os = null;
let detalhe_sensor = null;
let grau_suspeita = null;
let regra_suspeita_aplicada = null;

// ═══════════════════════════════════════════════════════════
// REGRA 1 (REVISADA): Suspeita de sensor/zona viciada via E130
// Usa e130_validos (já descartados os E130 com 9013 em ≤5min)
// ═══════════════════════════════════════════════════════════

if (String(codigoEvento || '').toUpperCase() === 'E130' && !primeiraOcorrencia) {

  // GRAU ALTA: >12 E130 válidos OU ≥3 dias distintos
  if (e130Validos7d > 12 || diasDistintosE130Validos7d >= 3) {
    grau_suspeita = 'alta';
    regra_suspeita_aplicada = e130Validos7d > 12
      ? `>12 E130 válidos na mesma zona em 7d (encontrados: ${e130Validos7d})`
      : `≥3 dias distintos com E130 válido (encontrados: ${diasDistintosE130Validos7d})`;
    prioridade_os = 'Alta';

  // GRAU MÉDIA: ≥8 E130 válidos em ≥2 dias distintos
  } else if (e130Validos7d >= 8 && diasDistintosE130Validos7d >= 2) {
    grau_suspeita = 'media';
    regra_suspeita_aplicada = `≥8 E130 válidos (${e130Validos7d}) em ≥2 dias distintos (${diasDistintosE130Validos7d})`;
    prioridade_os = 'Média';

  // GRAU BAIXA: ≥5 E130 válidos na mesma zona
  } else if (e130Validos7d >= 5) {
    grau_suspeita = 'baixa';
    regra_suspeita_aplicada = `≥5 E130 válidos na mesma zona em 7d (encontrados: ${e130Validos7d})`;
    prioridade_os = 'Baixa';

  // Fallback: manter regra antiga para hipóteses da IA
  } else if (
    hipotese.includes("sensor") ||
    observacaoRecorrencia.includes("sensor") ||
    pontosAtencao.includes("sensor")
  ) {
    grau_suspeita = 'baixa';
    regra_suspeita_aplicada = 'Indicação textual da IA (hipótese/observação contém "sensor")';
    prioridade_os = 'Baixa';
  }

  if (grau_suspeita) {
    abrir_os = true;
    tipo_os = "Sensor viciado";
    categoria_os = "Manutenção";
    detalhe_sensor = `Evento ${codigoEvento}${descricaoEvento ? " - " + descricaoEvento.trim() : ""}${zona ? " | zona " + zona : ""}`;
    motivo_os = `Suspeita de sensor viciado (grau: ${grau_suspeita}). ${regra_suspeita_aplicada}. ${detalhe_sensor}. E130 7d: total=${e130Total7d}, descartados(9013)=${e130Descartados7d}, válidos=${e130Validos7d}, dias distintos=${diasDistintosE130Validos7d}.`;
  }
}

// REGRA 2: falha técnica explícita (MANTIDA)
const eventoTecnico = ["9015", "E302", "E306", "E309", "E351"].includes(String(codigoEvento || "").toUpperCase());

if (!abrir_os && eventoTecnico && score >= 70) {
  abrir_os = true;
  tipo_os = "Falha técnica";
  categoria_os = "Manutenção";
  motivo_os = `Evento técnico ${codigoEvento}${descricaoEvento ? " - " + descricaoEvento.trim() : ""}${zona ? " | zona " + zona : ""} com score ${score}.`;
  prioridade_os = score >= 85 ? "Alta" : "Média";
}

// REGRA 3: recorrência operacional anormal (MANTIDA)
if (!abrir_os && !primeiraOcorrencia && mesmaZona7d >= 5 && score >= 70) {
  abrir_os = true;
  tipo_os = "Inspeção técnica";
  categoria_os = "Verificação";
  motivo_os = `Alta recorrência operacional${zona ? " na zona " + zona : ""}. Histórico 7d: mesma zona=${mesmaZona7d}.`;
  prioridade_os = "Média";
}

return {
  json: {
    ...j,
    codigo_evento: codigoEvento,
    setor,
    zona,
    patrimonio,
    patrimonio_norm: patrimonio,
    endereco,
    descricao_evento: descricaoEvento ? descricaoEvento.trim() : null,
    abrir_os,
    tipo_os,
    categoria_os,
    motivo_os,
    prioridade_os,
    detalhe_sensor,
    grau_suspeita,
    regra_suspeita_aplicada,
    e130_total_7d: e130Total7d,
    e130_descartados_9013_5m_7d: e130Descartados7d,
    e130_validos_sensor_7d: e130Validos7d,
    dias_distintos_e130_validos_7d: diasDistintosE130Validos7d
  }
};

const agora = new Date();
const dt48h = new Date(agora.getTime() - 48 * 60 * 60 * 1000);

return {
  json: {
    ...$input.item.json,
    janela_os_48h: dt48h.toISOString()
  }
};

// Input 1: dados preparados (Preparar Janela OS 48h)
// Input 2: resultado do Check Existing OS
const preparado = $('Preparar Janela OS 48h').first().json;
const osExistente = $('Check Existing OS').first().json;

// Verifica se o Check Existing OS retornou dados reais (tem id)
const temOSExistente = osExistente && osExistente.id;

return {
  json: {
    ...preparado,
    os_existente_id: temOSExistente ? osExistente.id : null,
    os_existente: temOSExistente ? osExistente : null
  }
};

// Gate E130 — Preparar dados mínimos para verificação de cooldown
const row = $('Get Row Supabase').first().json;

const codigoEvento = String(row.evento_codigo ?? '').trim().toUpperCase();
const patrimonioNorm = String(row.patrimonio_normalizado ?? row.patrimonio ?? '')
  .normalize('NFKC').trim().toUpperCase().replace(/\s+/g, ' ');
const zona = String(row.zona ?? '').trim();

const isE130 = codigoEvento === 'E130';

// Timestamps para cooldowns
const agora = new Date();
const cooldown60m = new Date(agora.getTime() - 60 * 60 * 1000).toISOString();
const cooldown48h = new Date(agora.getTime() - 48 * 60 * 60 * 1000).toISOString();

return [{
  json: {
    ...row,
    _gate: {
      is_e130: isE130,
      patrimonio_norm: patrimonioNorm,
      zona: zona,
      codigo_evento: codigoEvento,
      cooldown_60m_iso: cooldown60m,
      cooldown_48h_iso: cooldown48h
    }
  }
}];

// Avaliar os resultados dos cooldowns E130
const gateData = $('Gate E130 Prep').first().json;
const analiseItems = $('Check Cooldown Analise 60m').all();
const osItems = $('Check Cooldown OS 48h').all();

// Verificar se há análise recente (60 min)
const temAnaliseRecente = analiseItems.length > 0 && 
  analiseItems.some(i => i.json && Object.keys(i.json).length > 0 && i.json.id);

// Verificar se há OS recente (48h)
const temOSRecente = osItems.length > 0 && 
  osItems.some(i => i.json && Object.keys(i.json).length > 0 && i.json.id);

const bloqueado = temAnaliseRecente || temOSRecente;

let motivoBloqueio = null;
if (temAnaliseRecente && temOSRecente) {
  motivoBloqueio = 'Análise recente (60m) e OS aberta (48h) já existem para este contexto E130.';
} else if (temAnaliseRecente) {
  motivoBloqueio = 'Análise recente (60m) já existe para este contexto E130.';
} else if (temOSRecente) {
  motivoBloqueio = 'OS aberta (48h) já existe para este contexto E130.';
}

return [{
  json: {
    ...gateData,
    _gate: {
      ...gateData._gate,
      bloqueado: bloqueado,
      motivo_bloqueio: motivoBloqueio,
      tem_analise_recente: temAnaliseRecente,
      tem_os_recente: temOSRecente
    }
  }
}];

