const pendencia = $('Get Row Supabase').first().json;

// Histórico bruto
let historico = [];
try {
  const histItems = $('Get Supabase History').all().map(i => i.json);
  historico = histItems.filter(j => j && Object.keys(j).length > 0);
} catch (e) {
  historico = [];
}

// Resumo histórico
let historico_resumo = {
  janela_dias: 7,
  total_eventos_periodo: 0,
  mesmo_codigo_evento: 0,
  mesmo_setor: 0,
  mesma_zona: 0,
  mesmo_agrupamento: 0,
  primeira_ocorrencia: true,
  recorrencia_elevada_mesmo_setor: false,
  recorrencia_elevada_mesma_zona: false,
  recorrencia_elevada_mesmo_codigo: false,
  horarios_recorrentes: [],
  eventos_relevantes: [],
  resumo_historico_texto: 'Resumo histórico não disponível.'
};

try {
  const resumoNode = $('Resumo Histórico IA').first().json;
  if (resumoNode && resumoNode.historico_resumo) {
    historico_resumo = resumoNode.historico_resumo;
  }
} catch (e) {}

// Clima
let clima = {
  disponivel: false,
  temp: null,
  wind: null,
  code: null,
  text: "Não disponível"
};

try {
